import React, { useState } from "react";
import "./App.css";

// Available fraction blocks
const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#60A5FA", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#34D399", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#F87171", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#FBBF24", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#A78BFA", label: "1/8" },
];

// --- COMPONENT: FREE PLAY ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);
  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();
  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const data = e.dataTransfer.getData("fraction");
    if (data) {
      const frac = JSON.parse(data);
      const total = rows[rowIndex].reduce((s, f) => s + f.numerator / f.denominator, 0);
      if (total + (frac.numerator / frac.denominator) <= 1.01) {
        const nr = [...rows];
        nr[rowIndex].push({ ...frac, id: Math.random() });
        setRows(nr);
      }
    }
  };
  return (
    <div className="card">
      <p className="instruction-text">Drag blocks to make rows. Can you make them the same length? 🎈</p>
      <div className="toolbox">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      {rows.map((row, i) => (
        <div key={i} className="row-container">
          <div onDragOver={handleDragOver} onDrop={(e) => handleDrop(e, i)} className="drop-zone">
            {row.length === 0 && <span className="drop-zone-placeholder">Row {i+1}</span>}
            {row.map((b, bi) => (
              <div key={b.id} onClick={() => { const nr = [...rows]; nr[i].splice(bi,1); setRows(nr); }} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*100}%`, backgroundColor: b.color }}>{b.label}</div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: 'center' }}><button onClick={() => setRows([[],[],[]])} className="btn-danger">Clear</button></div>
    </div>
  );
}

// --- COMPONENT: COMPARISON GAME ---
function ComparisonGame() {
  const [left, setLeft] = useState(FRACTIONS[0]);
  const [right, setRight] = useState(FRACTIONS[2]);
  const [feedback, setFeedback] = useState("");

  const check = (choice) => {
    const lVal = left.numerator / left.denominator;
    const rVal = right.numerator / right.denominator;
    let correct = false;
    if (choice === ">") correct = lVal > rVal;
    if (choice === "<") correct = lVal < rVal;
    if (choice === "=") correct = Math.abs(lVal - rVal) < 0.001;

    setFeedback(correct ? "✅ Correct! Great job!" : "❌ Try again! Look at the sizes.");
  };

  const next = () => {
    setLeft(FRACTIONS[Math.floor(Math.random() * FRACTIONS.length)]);
    setRight(FRACTIONS[Math.floor(Math.random() * FRACTIONS.length)]);
    setFeedback("");
  };

  return (
    <div className="card">
      <p className="instruction-text">Which fraction is bigger? ⚔️</p>
      <div className="comparison-area">
        <div className="compare-box">
          <div className="fraction-block" style={{ backgroundColor: left.color, width: '120px', height: '80px', fontSize: '2rem' }}>{left.label}</div>
          <div style={{ width: '100%', height: '20px', background: left.color, marginTop: '10px', borderRadius: '4px', opacity: 0.3 }}></div>
        </div>
        <div className="vs-circle">VS</div>
        <div className="compare-box">
          <div className="fraction-block" style={{ backgroundColor: right.color, width: '120px', height: '80px', fontSize: '2rem' }}>{right.label}</div>
          <div style={{ width: '100%', height: '20px', background: right.color, marginTop: '10px', borderRadius: '4px', opacity: 0.3 }}></div>
        </div>
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', gap: '15px' }}>
        <button onClick={() => check(">")} className="btn-primary" style={{ fontSize: '2rem' }}>{'>'}</button>
        <button onClick={() => check("=")} className="btn-primary" style={{ fontSize: '2rem' }}>{'='}</button>
        <button onClick={() => check("<")} className="btn-primary" style={{ fontSize: '2rem' }}>{'<'}</button>
      </div>
      {feedback && <div style={{ textAlign: 'center', marginTop: '20px', fontSize: '1.2rem', fontWeight: 'bold' }}>
        {feedback} <br/> <button onClick={next} className="btn-primary" style={{ marginTop: '10px' }}>Next Battle</button>
      </div>}
    </div>
  );
}

// --- COMPONENT: NUMBER LINE ---
function NumberLine() {
  const [target, setTarget] = useState(0.5);
  const [userPos, setUserPos] = useState(0);
  const [message, setMessage] = useState("");

  const ticks = [0, 0.25, 0.5, 0.75, 1];
  const labels = ["0", "1/4", "1/2", "3/4", "1"];

  const check = () => {
    if (Math.abs(userPos - target) < 0.05) {
      setMessage("🎯 Bullseye! You found it!");
    } else {
      setMessage("Oops! Move the pin and try again.");
    }
  };

  return (
    <div className="card">
      <p className="instruction-text">Can you move the pin to <strong>{target === 0.5 ? "1/2" : target === 0.25 ? "1/4" : "3/4"}</strong> on the line? 📍</p>
      <div className="number-line-container">
        <div className="line-axis">
          {ticks.map((t, i) => (
            <div key={i} className="tick" style={{ left: `${t * 100}%` }}>
              <span className="tick-label">{labels[i]}</span>
            </div>
          ))}
          <div 
            className="pin" 
            style={{ left: `${userPos * 100}%` }}
            onMouseDown={(e) => {
              const move = (moveEvent) => {
                const rect = e.currentTarget.parentElement.getBoundingClientRect();
                const x = Math.max(0, Math.min(1, (moveEvent.clientX - rect.left) / rect.width));
                setUserPos(x);
              };
              const up = () => {
                window.removeEventListener('mousemove', move);
                window.removeEventListener('mouseup', up);
              };
              window.addEventListener('mousemove', move);
              window.addEventListener('mouseup', up);
            }}
          >📍</div>
        </div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '40px' }}>
        <button onClick={check} className="btn-primary">Check My Spot</button>
        {message && <p style={{ fontWeight: 'bold', marginTop: '10px' }}>{message}</p>}
        <button onClick={() => { setTarget([0.25, 0.5, 0.75][Math.floor(Math.random()*3)]); setMessage(""); }} className="btn-primary" style={{ marginLeft: '10px' }}>New Spot</button>
      </div>
    </div>
  );
}

// --- COMPONENT: EQUIVALENTS ---
function EquivalentsFinder() {
  const [target] = useState({ label: "1/2", val: 0.5, color: "#60A5FA" });
  const [blocks, setBlocks] = useState([]);
  const currentTotal = blocks.reduce((s, f) => s + f.numerator/f.denominator, 0);

  const handleDragStart = (e, f) => e.dataTransfer.setData("fraction", JSON.stringify(f));
  const handleDragOver = (e) => e.preventDefault();
  const handleDrop = (e) => {
    e.preventDefault();
    const data = JSON.parse(e.dataTransfer.getData("fraction"));
    if (currentTotal + (data.numerator/data.denominator) <= 0.501) {
      setBlocks([...blocks, { ...data, id: Math.random() }]);
    }
  };

  return (
    <div className="card">
      <p className="instruction-text">Find other ways to make <strong>{target.label}</strong>! 🧩</p>
      <div className="match-target" style={{ backgroundColor: target.color + '22' }}>Goal: {target.label}</div>
      <div className="toolbox">
        {FRACTIONS.filter(f => f.denominator > 2).map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div onDragOver={handleDragOver} onDrop={handleDrop} className="drop-zone" style={{ width: '50%', margin: '0 auto' }}>
        {blocks.map(b => (
          <div key={b.id} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*200}%`, backgroundColor: b.color }}>{b.label}</div>
        ))}
      </div>
      {Math.abs(currentTotal - 0.5) < 0.01 && <h3 style={{ textAlign: 'center', color: 'var(--success)' }}>🎉 Match! Did you know {blocks.length} pieces of {blocks[0].label} make {target.label}?</h3>}
      <button onClick={() => setBlocks([])} className="btn-danger" style={{ display: 'block', margin: '20px auto' }}>Reset</button>
    </div>
  );
}

// --- COMPONENT: FRACTION KITCHEN ---
function FractionKitchen() {
  const [recipe, setRecipe] = useState({ name: "Magic Cookie Dough", target: 0.75, unit: "cup" });
  const [bowlAmount, setBowlAmount] = useState(0);

  const add = (val) => {
    if (bowlAmount + val <= 1.01) setBowlAmount(bowlAmount + val);
    else alert("Bowl is overflowing! 🥣");
  };

  return (
    <div className="card">
      <p className="instruction-text">Welcome to the Fraction Kitchen! Bake with math. 🍪</p>
      <div className="kitchen-container">
        <div className="recipe-card">
          <h3>📜 Recipe: {recipe.name}</h3>
          <p>We need exactly <strong>{recipe.target === 0.75 ? "3/4" : "1 Whole"}</strong> cup of flour.</p>
          <p>Current: {Math.round(bowlAmount * 100) / 100} cups</p>
        </div>
        <div className="bowl-area">
          <div className="mixing-bowl">
            <div className="bowl-fill" style={{ height: `${bowlAmount * 100}%` }}></div>
          </div>
          <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
            <button onClick={() => add(0.25)} className="btn-primary">Add 1/4 Cup</button>
            <button onClick={() => add(0.5)} className="btn-primary">Add 1/2 Cup</button>
          </div>
          {Math.abs(bowlAmount - recipe.target) < 0.01 && <h2 style={{ color: 'var(--success)' }}>🎉 Perfect! Time to bake!</h2>}
          <button onClick={() => setBowlAmount(0)} className="btn-danger" style={{ marginTop: '20px' }}>Empty Bowl</button>
        </div>
      </div>
    </div>
  );
}

// --- MAIN APP COMPONENT ---
export default function App() {
  const [activeTab, setActiveTab] = useState("free");

  const tabs = [
    { id: "free", label: "🎈 Play", color: "var(--primary)" },
    { id: "compare", label: "⚔️ Battle", color: "var(--secondary)" },
    { id: "line", label: "📍 Line", color: "var(--accent)" },
    { id: "match", label: "🧩 Match", color: "var(--success)" },
    { id: "kitchen", label: "🥣 Bake", color: "var(--warning)" }
  ];

  return (
    <div className="app-container">
      <h1 className="app-title">🍕 Fraction Fun! 🍕</h1>
      <div className="nav-menu" style={{ flexWrap: 'wrap', borderRadius: '20px' }}>
        {tabs.map(t => (
          <button 
            key={t.id}
            onClick={() => setActiveTab(t.id)} 
            className={`nav-button ${activeTab === t.id ? "active" : ""}`}
            style={{ backgroundColor: activeTab === t.id ? t.color : '' }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {activeTab === "free" && <FreePlay />}
      {activeTab === "compare" && <ComparisonGame />}
      {activeTab === "line" && <NumberLine />}
      {activeTab === "match" && <EquivalentsFinder />}
      {activeTab === "kitchen" && <FractionKitchen />}
    </div>
  );
}
